mapper.select:
SELECT a.id userId, a.UserName AS realName, b.accountname AS username, b.accountpwd AS password, (case when b.accountstatus = 1 then true else false end) AS enabled, a.user_type AS UserType, b.nickname, HeadImage, a.phonenum FROM sys_user a INNER JOIN sys_account b ON a.id = b.UserId WHERE a.IsDeleted = false
AND a.phonenum = #{phoneNum,jdbcType=VARCHAR}
AND b.accountname = #{userName,jdbcType=VARCHAR}
